import{_ as r,o as t,c as o,j as e,a as s,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const u=JSON.parse('{"title":"星辰之冠","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/3.B级/星辰之冠.md","filePath":"4.资源分区/7.物品与装备/4.奇物/3.B级/星辰之冠.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/3.B级/星辰之冠.md"};function p(i,a,l,_,b,c){return t(),o("div",null,[...a[0]||(a[0]=[e("h1",{id:"星辰之冠",tabindex:"-1"},[s("星辰之冠 "),e("a",{class:"header-anchor",href:"#星辰之冠","aria-label":'Permalink to "星辰之冠"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"灵魂蓝调014")])])],-1),n('<h1 id="星辰之冠-1" tabindex="-1">星辰之冠 <a class="header-anchor" href="#星辰之冠-1" aria-label="Permalink to &quot;星辰之冠&quot;">​</a></h1><p>星辰之冠<br> B+4000<br> 魔幻本质<br> 一顶小巧透明的冠冕，以晶莹剔透的晶体雕琢而成，璀璨夺目，宛如将整个夜空的星辉都定格在了这一顶小巧的冠冕中。似乎是从哪个宇宙传说中淘来的秘宝，据说记载着一位与星辰紧密相连的少女的宿命。这位少女曾徘徊在星与夜的尽头，编织着无尽的命运线索，但现在她的故事早已化作泡影，伴随她的足迹一同消失于历史的长河之中。</p><p>概念武装，当你戴上它后，会化为一顶璀璨冠冕的虚影以合适的姿态斜戴在你的头上，并会在夜空中与头顶的星空交相辉映，即使使用者戴着头盔它也会以合适的姿态在头盔上安置，因此并不占据头盔位，同时也不会对使用者带来任何重量上的负担。</p><p>星海回忆 (Memories of the Starsea)<br> &quot;当夜空的幕布垂落，她曾在星光间起舞，那些闪烁的光点是她唯一的伙伴。&quot;<br> 佩戴者能够唤醒星辰的回忆，短暂连接星海深处的神秘力量。在夜晚的星空下，每当佩戴者进入冥想或使用占星类能力时，会获得一颗在皇冠中闪烁的星辉。这粒星辉可用于强化她的感知，或使其能够短暂地对命运进行干涉。<br> 使用这颗星辉后，使用者的敏感范围提升一倍。</p><p>宿命交织 (Fate&#39;s Twine)<br> &quot;她的命运与星辰交织，编织着不属于尘世的线索。没有人知道，这线索究竟指向何方。&quot;<br> 每当佩戴者命中敌人时，有几率触发星辰的命运丝线，使其下一次攻击带有附加的星辰之力，命中的同时会造成额外伤害。<br> 使用者的攻击获得【湮灭】，当本次触发湮灭成功的效果后，佩戴者会承受1点不可豁免的晕眩点数，仿佛命运扭转留下的余波。</p><p>星尘挽歌 (Stardust&#39;s Lament)<br> &quot;她的眼泪化作星屑洒落大地，但无人知晓那泪水中究竟埋藏着什么秘密。&quot;<br> 每当佩戴者承受致命伤害时，星辰的力量将凝聚成一片星屑护盾，吸收部分即将到来的伤害。护盾的星光闪烁虽短暂，但每片星屑消逝后，佩戴者将获得星光的反哺，使其下一次施展的能力获得强化效果。<br> 每天一次，当受到足以致命的伤害时，使用者会获得20点临时生命以抵挡该伤害，之后，每2点因此失去的临时生命，都使你的下一次攻击增加1点附加成功。之后无论是否耗尽，该能力提供的临时生命都会消失。每当夜晚降临后，这个能力会自动充能完毕。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const f=r(d,[["render",p]]);export{u as __pageData,f as default};
